INSERT INTO "benchmark_results" VALUES(1,NULL,NULL,'2026-05-20',NULL,NULL,NULL,NULL,'Benchmark organization refactor','Documentation',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Methodology/documentation change only; benchmark sources are now grouped into core hot path, realistic flow, stress, determinism/replay, and experimental reserve-sweep categories. No new EC2 performance results were recorded for this row.','docs/benchmark_history.md',NULL);
INSERT INTO "benchmark_results" VALUES(2,NULL,'eb048b5','2026-05-20T04:52:47Z','AWS EC2 `t3.small`, Ubuntu 26.04, Linux 7.0.0-1004-aws, Intel Xeon Platinum 8259CL, GCC 15.2.0','GCC 15.2.0','Release','-O3 -DNDEBUG','OrderBook level create/delete churn','Stress','10,000 timed operations',NULL,409572.0,409456.0,24423000.0,NULL,NULL,NULL,NULL,NULL,'Direct OrderBook hot path only; fixed-seed interleaved bid/ask tiny-level create/delete cycles, stable opposite-side guard liquidity, caller-owned reusable event buffer, reserve capacity 1,024, preload orders 128, max live orders 131. 124/124 correctness tests passed first. Source synced without `.git`, build dirs, `.DS_Store`, or macOS `._*` sidecar files.','docs/benchmark_history.md',NULL);
INSERT INTO "benchmark_results" VALUES(3,NULL,'eb048b5','2026-05-20T04:52:47Z','AWS EC2 `t3.small`, Ubuntu 26.04, Linux 7.0.0-1004-aws, Intel Xeon Platinum 8259CL, GCC 15.2.0','GCC 15.2.0','Release','-O3 -DNDEBUG','OrderBook level create/delete churn','Stress','100,000 timed operations',NULL,4214671.0,4215927.0,23720000.0,NULL,NULL,NULL,NULL,NULL,'Median across 5 pinned Google Benchmark repetitions; 24,975 churn cycles; half bid-side and half ask-side levels; final level erasure split between cancel and matching delete paths.','docs/benchmark_history.md',NULL);
